out = []
for v in (value or []):
	v = v or {}
	vnum = v.get('VersionNumber', 0)
	pub = v.get('PublishedAt')
	dep = v.get('DeprecatedAt')
	if dep is not None:
		status = 'Deprecated'
	elif pub is None:
		status = 'Draft'
	else:
		status = 'Published'
	effDisp = v.get('effectiveFromDisplay') or ''
	label = 'v' + str(vnum) + ' — ' + status
	if effDisp:
		label = label + ' (Eff ' + effDisp + ')'
	out.append({'label': label, 'value': v.get('Id')})
return out

attrs = BlueRidge.Common.Util.extractQualifiedValues(value) or []
state = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.state) or {}
editDraft = state.get('editDraft') or {}
status = editDraft.get('status') or ''
if status == 'Draft':
	mode = 'draft'
elif status == 'Deprecated':
	mode = 'deprecated'
else:
	mode = 'published'
uoms = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.uoms) or []
dataTypes = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.dataTypes) or []
total = len(attrs)
out = []
for i, a in enumerate(attrs):
	a = a or {}
	out.append({'attribute': a, 'rowIndex': i, 'attrCount': total, 'mode': mode, 'uoms': uoms, 'dataTypes': dataTypes})
return out

rows = BlueRidge.Common.Util.extractQualifiedValues(value) or []
out = []
for v in rows:
	v = v or {}
	pub = v.get('PublishedAt')
	dep = v.get('DeprecatedAt')
	if dep is not None:
		state = 'Deprecated'
	elif pub is None:
		state = 'Draft'
	else:
		state = 'Published'
	out.append({
		'Version': 'v' + str(v.get('VersionNumber') or ''),
		'EffectiveFrom': v.get('effectiveFromDisplay') or '',
		'DeprecatedAt': str(dep)[:10] if dep is not None else '—',
		'State': state,
		'CreatedBy': v.get('CreatedByName') or v.get('CreatedBy') or '',
		'CreatedAt': str(v.get('CreatedAt'))[:16] if v.get('CreatedAt') is not None else ''
	})
return out

customMethods.script:
incoming = self.view.params.specId
if not incoming:
	try:
		incoming = self.session.custom.qsIncomingSpecId
	except Exception:
		incoming = None
if incoming:
	self.view.custom.incomingSpecId = incoming
	self.view.custom.selectedSpecId = incoming

return {
	"id": None, "name": "", "description": "",
	"itemId": None, "itemCode": "", "itemDesc": "",
	"operationTemplateId": None, "opCode": "", "deprecatedAt": None,
}

return {
	"id": None, "specId": None, "versionNumber": None,
	"effectiveFrom": None, "effectiveFromDisplay": "",
	"publishedAt": None, "deprecatedAt": None,
	"status": None, "attributes": [],
}

specId = self.view.custom.selectedSpecId
self.view.custom.activeVersionId = None
if not specId:
	self.view.custom.specHeader = {"selected": self._emptyHeader(), "editDraft": self._emptyHeader()}
	self.view.custom.state = {"selected": self._emptyVersion(), "editDraft": self._emptyVersion()}
	self.view.custom.versions = []
	return
header = BlueRidge.Quality.QualitySpec.getSpecHeader(specId)
self.view.custom.specHeader = {"selected": dict(header), "editDraft": dict(header)}
self.view.custom.uoms = BlueRidge.Quality.QualitySpec.listUoms()
versions = BlueRidge.Quality.QualitySpec.listVersions(specId, True)
self.view.custom.versions = versions
if versions:
	self.view.custom.activeVersionId = versions[0].get("Id")
else:
	self.view.custom.state = {"selected": self._emptyVersion(), "editDraft": self._emptyVersion()}

vid = self.view.custom.activeVersionId
if not vid:
	self.view.custom.state = {"selected": self._emptyVersion(), "editDraft": self._emptyVersion()}
	return
bundle = BlueRidge.Quality.QualitySpec.getVersionFull(vid)
self.view.custom.state = {"selected": bundle, "editDraft": self._clone(bundle)}

draft = self.view.custom.specHeader.editDraft or {}
name = (draft.get("name") or "").strip()
if not name:
	BlueRidge.Common.Notify.toast("Name required", "Enter a spec name before saving.", "warning")
	return
res = BlueRidge.Quality.QualitySpec.updateSpecHeader(draft)
BlueRidge.Common.Ui.notifyResult(res, "Spec saved")
if res and res.get("Status"):
	saved = dict(draft)
	self.view.custom.specHeader = {"selected": dict(saved), "editDraft": dict(saved)}
	self.refreshSpecs()

system.perspective.openPopup(
	id="mpp-confirm-unsaved",
	view="BlueRidge/Components/Popups/ConfirmUnsaved",
	modal=True,
	showCloseIcon=False,
	params={
		"title": "Unsaved Changes",
		"message": "You have unsaved changes to this quality spec. Save before switching?",
	},
)

messageHandlers.script:
if not payload:
	return
newId = payload.get("specId")
if newId == self.view.custom.selectedSpecId:
	return
if self.view.custom.isDirty:
	self.view.custom.pendingSwitch = newId
	self.openUnsavedConfirm()
else:
	self.view.custom.selectedSpecId = newId

if not payload:
	return
action = payload.get("action")
pending = self.view.custom.pendingSwitch
if action == "cancel":
	self.view.custom.pendingSwitch = None
	return
if action == "save":
	draftStatus = (self.view.custom.state.editDraft or {}).get("status")
	if draftStatus == "Draft":
		self.handleSaveDraft()
	self.handleSaveHeader()
elif action == "discard":
	self.view.custom.specHeader = {"selected": dict(self.view.custom.specHeader.selected), "editDraft": dict(self.view.custom.specHeader.selected)}
	self.view.custom.state = {"selected": self._clone(self.view.custom.state.selected), "editDraft": self._clone(self.view.custom.state.selected)}
if pending is not None:
	self.view.custom.pendingSwitch = None
	self.view.custom.selectedSpecId = pending

if not payload or payload.get("action") != "confirm":
	return
specId = self.view.custom.selectedSpecId
if not specId:
	return
res = BlueRidge.Quality.QualitySpec.deprecateSpec(specId)
BlueRidge.Common.Ui.notifyResult(res, "Spec deprecated")
if res and res.get("Status"):
	self.view.custom.selectedSpecId = None
	self.refreshSpecs()

if not payload or payload.get("action") != "confirm":
	return
draft = self.view.custom.state.editDraft or {}
vid = draft.get("id")
if not vid:
	return
res = BlueRidge.Quality.QualitySpec.discardDraft(vid)
BlueRidge.Common.Ui.notifyResult(res, "Draft discarded")
if res and res.get("Status"):
	self.view.custom.activeVersionId = None
	self.refreshVersions()
	self.refreshSpecs()
	vers = self.view.custom.versions or []
	if vers:
		self.view.custom.activeVersionId = vers[0].get("Id")

if not payload or payload.get("action") != "confirm":
	return
sel = self.view.custom.state.selected or {}
vid = sel.get("id")
if not vid:
	return
res = BlueRidge.Quality.QualitySpec.deprecateVersion(vid)
BlueRidge.Common.Ui.notifyResult(res, "Version deprecated")
if res and res.get("Status"):
	self.refreshVersions()
	self.loadActiveVersion()
	self.refreshSpecs()
